"use client";

/**
 * Opener for the `resourcePickerWindow` overlay.
 *
 * - `useOpenResourcePickerWindow()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<ResourcePickerWindowController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "resourcePickerWindow" as const;

export interface OpenResourcePickerWindowOptions {
  /** TODO callback — wire via callback registry in stage 3. */
  onResourceSelected?: (...args: unknown[]) => void;
  /** TODO: tighten to `{
    supportsImageUrls?: boolean;
    supportsFileUrls?: boolean;
    supportsYoutubeVideos?: boolean;
    supportsAudio?: boolean;
  }` once that type is imported. */
  attachmentCapabilities?: unknown;
  /** TODO callback — wire via callback registry in stage 3. */
  onSettingsClick?: () => void;
  /** TODO callback — wire via callback registry in stage 3. */
  onDebugClick?: () => void;
  showDebugActive?: boolean;
  width?: number;
  height?: number;
  /** TODO: tighten to `WindowPosition` once that type is imported. */
  position?: unknown;
}

export interface ResourcePickerWindowHandle {
  close: () => void;
}

export function useOpenResourcePickerWindow() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenResourcePickerWindowOptions = {}): ResourcePickerWindowHandle => {
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          data: {
            onResourceSelected: opts.onResourceSelected,
            attachmentCapabilities: opts.attachmentCapabilities,
            onSettingsClick: opts.onSettingsClick,
            onDebugClick: opts.onDebugClick,
            showDebugActive: opts.showDebugActive,
            width: opts.width,
            height: opts.height,
            position: opts.position,
          },
        }),
      );
      return {
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function ResourcePickerWindowController(props: OpenResourcePickerWindowOptions): null {
  const open = useOpenResourcePickerWindow();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.onResourceSelected, props.attachmentCapabilities, props.onSettingsClick, props.onDebugClick, props.showDebugActive, props.width, props.height, props.position]);
  return null;
}
